#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define ll long long#define nl "\n"#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = 1e9+10; void solve(){    string s;    cin>>s;    ll m;    cin>>m;    string l,r;    cin>>l>>r;    ll pos = 0;    for(int i=0; i<m; i++){        ll farthest = pos;        for(char d=l[i]; d<=r[i]; d++){            ll find = s.find(d, pos);    // find digit (d) in s starting from pos             if(find==string::npos){  // d doesn't exist in remaining part s                cout<<"YES\n";                return;            }             farthest = max(farthest, find+1);        }        pos = farthest;  // move to farthest position for next iteration    }    cout<<"NO\n";} int main(){    FASTER    ll t;    cin>>t;    while(t--){        solve();    }}